record_types.code:
type Stats_Type is record
   Bytes    : Uint64 := 0;
   Packets  : Uint32 := 0;
   Dropped  : Uint32 := 0;
   Ignored  : Uint32 := 0;
end record;

tagged_types.code:
type Ifnet_Type is abstract tagged limited record
   Mac      : Ether_Addr := (0, 16#81#, 16#E1#, others => 0);
   Ip       : Ip_Addr := (others => 0);
   Netmask  : Ip_Addr := (255, 255, 255, 0);
   Gateway  : Ip_Addr := (others => 0);
   Dns      : Ip_Addr := (others => 0);
   Mtu      : Ip_Length := 1500;
   Rx_Stats : Stats_Type;
   Tx_Stats : Stats_Type;
end record;
